import moment from '@lark/moment-timezone-polyfill'

export default moment.defineLocale('zh-HK', {
  months: '一月_二月_三月_四月_五月_六月_七月_八月_九月_十月_十一月_十二月'.split(
    '_'
  ),
  monthsShort: '1月_2月_3月_4月_5月_6月_7月_8月_9月_10月_11月_12月'.split(
    '_'
  ),
  weekdays: '星期日_星期一_星期二_星期三_星期四_星期五_星期六'.split('_'),
  weekdaysShort: '週日_週一_週二_週三_週四_週五_週六'.split('_'),
  weekdaysMin: '日_一_二_三_四_五_六'.split('_'),
  longDateFormat: {
    LT: 'HH:mm',
    LTS: 'D日 ddd',
    L: 'YYYY年M月',
    LL: 'YYYY年MMMD日',
    LLL: 'M月D日',
    LLLL: 'YYYY年MMMD日 (ddd)',
    l: 'YYYY年M月',
    ll: 'M月D日 (ddd)',
    lll: 'YYYY年MMMD日 HH:mm',
    llll: 'YYYY年MMMD日 (ddd) HH:mm',
  },
  meridiemParse: /上午|下午/,
  meridiemHour: (hour, meridiem) => {
    if (hour === 12) {
      hour = 0
    }
    let returnString
    if (meridiem === '上午') {
      returnString = hour
    } else if (meridiem === '下午') {
      returnString = hour + 12
    }

    return returnString
  },
  meridiem: function (hour, minute, isLower) {

    if (hour < 12) {
      return '上午'
    } else{
      return '下午'
    }
  },
  calendar: {
    sameDay: '[今天]',
    nextDay: '[明天]',
    nextWeek: '[下]ddddLT',
    lastDay: '[昨天]',
    lastWeek: '[上]ddddLT',
    sameElse: 'L',
  },
  dayOfMonthOrdinalParse: /\d{1,2}(日|月|週)/,
  ordinal: function (number, period) {
    switch (period) {
      case 'd':
    case 'D':
    case 'DDD':
      return number + '日'
      case 'M':
      return number + '月'
      case 'w':
    case 'W':
      return number + '週'
      default:
        return number
    }
  },
  relativeTime: {
    future: '%s後',
    past: '%s前',
    s: '幾秒',
    ss: '%d 秒',
    m: '1 分鐘',
    mm: '%d 分鐘',
    h: '1 小時',
    hh: '%d 小時',
    d: '1 天',
    dd: '%d 天',
    M: '1 个個',
    MM: '%d 个個',
    y: '1 年',
    yy: '%d 年',
  },
} as any as moment.LocaleSpecification)
