//! moment.js locale configuration
//! locale : English (United Kingdom) [en-gb]
//! author : Chris Gedrim : https://github.com/chrisgedrim

import moment from '@lark/moment-timezone-polyfill'

export default moment.defineLocale('en-US', {
  months: 'January_February_March_April_May_June_July_August_September_October_November_December'.split(
    '_'
  ),
  monthsShort: 'Jan_Feb_Mar_Apr_May_Jun_Jul_Aug_Sep_Oct_Nov_Dec'.split('_'),
  weekdays: 'Sunday_Monday_Tuesday_Wednesday_Thursday_Friday_Saturday'.split('_'),
  weekdaysShort: 'Sun_Mon_Tue_Wed_Thu_Fri_Sat'.split('_'),
  weekdaysMin: 'Su_Mo_Tu_We_Th_Fr_Sa'.split('_'),
  longDateFormat: {
    LT: 'HH:mm', // 可用
    LTS: 'ddd, Do',
    L: 'MMMM YYYY',
    LL: 'MMM D, YYYY',
    LLL: 'MMM D',
    LLLL: 'ddd, MMM D, YYYY', // 千万不要改，除非你知道自己在干嘛
    l: 'MMM YYYY',
    ll: 'ddd, MMM D', // 千万不要改，除非你知道自己在干嘛
    lll: 'MMMM D, YYYY HH:mm',
    llll: 'ddd, MMM D, YYYY HH:mm', // 可用
  },
  meridiemParse: /AM|PM/,
  meridiemHour: (hour, meridiem) => {
    if (hour === 12) {
      hour = 0
    }
    let returnString
    if (meridiem === 'AM') {
      returnString = hour
    } else if (meridiem === 'PM') {
      returnString = hour + 12
    }

    return returnString
  },
  meridiem: (hour, minute, isLower) => {
    const hm = hour * 100 + minute
    let returnString
    if (hm < 1200) {
      returnString = 'AM'
    } else {
      returnString = 'PM'
    }
    return returnString
  },
  calendar: {
    sameDay: '[Today]',
    nextDay: '[Tomorrow]',
    nextWeek: 'dddd [at] LT',
    lastDay: '[Yesterday]',
    lastWeek: '[Last] dddd [at] LT',
    sameElse: 'L',
  },
  relativeTime: {
    future: 'in %s',
    past: '%s ago',
    s: (number, withoutSuffix, key, isFuture) => {
      let returnString
      if (number === 0) {
        returnString = 'When the event starts'
      } else {
        returnString = 'a few seconds'
      }
      return returnString
    },
    m: 'a minute',
    mm: '%d minutes',
    h: 'an hour',
    hh: '%d hours',
    d: 'a day',
    dd: '%d days',
    M: 'a month',
    MM: '%d months',
    y: 'a year',
    yy: '%d years',
  },
  dayOfMonthOrdinalParse: /\d{1,2}(st|nd|rd|th)/,
  ordinal: (number) => {
    const b = number % 10
    const output =
            ~~((number % 100) / 10) === 1
              ? 'th'
              : b === 1 ? 'st' : b === 2 ? 'nd' : b === 3 ? 'rd' : 'th'
    return number + output
  },
  week: {
    dow: 0, // Monday is the first day of the week.
    doy: 4, // The week that contains Jan 4th is the first week of the year.
  },
} as any as moment.LocaleSpecification)
